exec("""from __future__ import annotations\nimport re\nfrom dataclasses import asdict, dataclass\nfrom typing import Mapping\n@dataclass(frozen=True)\nclass MatchCheck:\n    check_name: str\n    passed: bool\n    evidence: str\n@dataclass(frozen=True)\nclass MatchResult:\n    jan_exact: bool\n    title_model_match: bool\n    variant_safe: bool\n    score: int\n    status: str\n    checks: list[MatchCheck]\n    warning: str\n    def to_dict(self):\n        d = asdict(self); return d\ndef normalize_text(v):\n    return re.sub(r'\\s+', ' ', re.sub(r'[\\[\\]（）()【】,，:：/・\\\\|_-]+', ' ', str(v or '').casefold().replace('　',' '))).strip()\ndef tokens(v):\n    return {t for t in re.findall(r'[a-z0-9]+|[ぁ-んァ-ン一-龥ー]+', normalize_text(v)) if len(t) >= 2}\ndef capacities(v):\n    return set(re.findall(r'\\d+(?:GB|TB)', normalize_text(v).upper().replace(' ', '')))\ndef colors(v):\n    text = normalize_text(v); m = {'silver':['silver','シルバー'], 'blue':['blue','ブルー','ディープブルー'], 'orange':['orange','オレンジ'], 'white':['white','ホワイト'], 'black':['black','ブラック','グレー'], 'red':['red','レッド'], 'yellow':['yellow','イエロー'], 'pink':['pink','コーラル'], 'gold':['gold','ゴールド']}\n    return {k for k, vals in m.items() if any(x in text for x in vals)}\ndef codes(v):\n    return set(re.findall(r'\\b[A-Z]{1,5}-?\\d{3,}[A-Z0-9-]*\\b', normalize_text(v).upper()))\ndef get(m: Mapping[str, object], *keys):\n    for k in keys:\n        if m.get(k) is not None:\n            return str(m.get(k))\n    return ''\ndef overlap(a,b):\n    ta, tb = tokens(a), tokens(b)\n    return len(ta & tb) / max(len(ta), 1) if ta and tb else 0.0\ndef triple_check_product(enoking_product: Mapping[str, object], supplier_offer: Mapping[str, object]) -> MatchResult:\n    ej = get(enoking_product, 'jan', 'JAN').strip(); sj = get(supplier_offer, 'jan', 'JAN', 'supplier_jan').strip(); en = get(enoking_product, 'product_name','name','title'); sn = get(supplier_offer, 'supplier_product_name','product_name','title','itemName'); blob = ' '.join([sj, sn, get(supplier_offer,'url','itemUrl')])\n    jan = bool(ej and (sj == ej or ej in blob)); title_score = overlap(en, sn); code_ok = bool(codes(en) and codes(en) <= codes(sn)); title = jan or title_score >= 0.45 or code_ok\n    cap_conflict = bool(capacities(en) and capacities(sn) and capacities(en) != capacities(sn)); color_conflict = bool(colors(en) and colors(sn) and colors(en).isdisjoint(colors(sn))); variant = not cap_conflict and not color_conflict\n    score = (3 if jan else 0) + (2 if title else 0) + (2 if variant else 0)\n    status = 'VERIFIED_EXACT_TRIPLE_CHECKED' if jan and title and variant else ('LIKELY_MATCH_NEEDS_MANUAL_JAN_CONFIRM' if score >= 4 and variant else 'REJECT_OR_MANUAL_REVIEW')\n    warning = 'JAN・名称/型番・バリエーションの3点チェック済み' if status == 'VERIFIED_EXACT_TRIPLE_CHECKED' else '購入前にJAN・型番・色・容量を目視確認してください。'\n    checks = [MatchCheck('1_JAN_EXACT', jan, f'{ej}/{sj}'), MatchCheck('2_TITLE_MODEL', title, f'overlap={title_score:.2f}'), MatchCheck('3_VARIANT_SAFE', variant, f'capacity_conflict={cap_conflict} color_conflict={color_conflict}')]\n    return MatchResult(jan, title, variant, score, status, checks, warning)\n""")